    mediaRecorder.start();

    // Defer play to allow recorder to spin up
    setTimeout(() => {
      setIsPlaying(true);
    }, 100);
  };

  // Convert hex to [R, G, B, A] for WASM WebGL
  const hexToRgba = (hex: string) => {
    const r = parseInt(hex.slice(1, 3), 16) / 255;
    const g = parseInt(hex.slice(3, 5), 16) / 255;
    const b = parseInt(hex.slice(5, 7), 16) / 255;
    return [r, g, b, 1.0];
  };

  // Convert [R, G, B, A] to hex for input[type=color]
  const rgbaToHex = (colorArray: number[] | undefined) => {
    if (!colorArray || colorArray.length < 3) return "#4f46e5";
    const r = Math.round(colorArray[0] * 255).toString(16).padStart(2, '0');
    const g = Math.round(colorArray[1] * 255).toString(16).padStart(2, '0');
    const b = Math.round(colorArray[2] * 255).toString(16).padStart(2, '0');
    return `#${r}${g}${b}`;
  };

  const lastTimeRef = useRef<number>(0);
  const frameRef = useRef(frame);
  const isPlayingRef = useRef(isPlaying);
  const isExportingRef = useRef(isExporting);
  const durationRef = useRef(projectData.duration_frames || 100);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const audioDestRef = useRef<MediaStreamAudioDestinationNode | null>(null);
  const activeSourcesRef = useRef<AudioBufferSourceNode[]>([]);
  const recordedChunksRef = useRef<Blob[]>([]);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);

  // Sync refs to state so rAF callback can read fresh values without re-binding
  // eslint-disable-next-line react-hooks/immutability
  useEffect(() => { frameRef.current = frame; }, [frame]);
  useEffect(() => { isPlayingRef.current = isPlaying; }, [isPlaying]);
  useEffect(() => { isExportingRef.current = isExporting; }, [isExporting]);
  useEffect(() => { durationRef.current = projectData.duration_frames || 100; }, [projectData]);



  useEffect(() => {
    let rafId: number;

    const tick = (time: number) => {
      if (!lastTimeRef.current) lastTimeRef.current = time;
      const dt = time - lastTimeRef.current;

      if (isPlayingRef.current) {
        // Assume 60fps, 1000ms / 60 = 16.66ms per frame
        const framesToAdvance = Math.floor(dt / (1000 / 60));

        if (framesToAdvance > 0) {
          let nextFrame = frameRef.current + framesToAdvance;
          if (nextFrame >= durationRef.current) {
            nextFrame = 0; // loop
            if (isExportingRef.current) {
              if (mediaRecorderRef.current && mediaRecorderRef.current.state === "recording") {
                mediaRecorderRef.current.stop();
              }
              // Stop playing when export finishes
              // This requires a state update outside rAF to be safe, but since we rely on refs, we can just do:
              // Actually we can set nextFrame to durationRef.current so it renders the last frame.
              nextFrame = durationRef.current; 
            }
          }
          setFrame(nextFrame);
          lastTimeRef.current = time;

          if (isExportingRef.current) {
            setExportProgress(Math.floor((nextFrame / durationRef.current) * 100));
          }
        }
      } else {
        lastTimeRef.current = time;
      }

      rafId = requestAnimationFrame(tick);
    };

    rafId = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafId);
  }, []);

  // Web Audio API Playback sync
  useEffect(() => {
    if (isPlaying) {
      if (!audioCtxRef.current) {
        // eslint-disable-next-line @typescript-eslint/no-unsafe-type-assertion
        audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }

      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') ctx.resume();

      const fps = projectData.fps || 60;

      // Find all audio/video clips in project
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const anyTrackSoloed = (projectData.tracks || []).some((t: any) => t.isSoloed);
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      (projectData.tracks || []).forEach((track: any) => {
        if (track.isHidden || track.isMuted) return; // Skip audio for hidden or muted tracks
        if (anyTrackSoloed && !track.isSoloed) return; // Skip non-soloed tracks if any track is soloed

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        (track.clips || []).forEach((clip: any) => {
          if (clip.isDisabled) return;
          if (clip.type === "audio" || clip.type === "video") {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const asset = assets.find((a: any) => a.id === clip.id || a.name === clip.name);
            if (asset && asset.audioBuffer) {
              const source = ctx.createBufferSource();
              source.buffer = asset.audioBuffer;

              const gainNode = ctx.createGain();

              const currentLocalFrame = frameRef.current - clip.start_frame;
              const clipStartInSeconds = clip.start_frame / fps;
              const currentSeconds = frameRef.current / fps;

              // Calculate initial playback offset by integrating playback_rate
              let initialMediaFrame = clip.media_offset_frames || 0;
              // eslint-disable-next-line @typescript-eslint/no-explicit-any
              const hasSpeedKeyframes = clip.keyframes && clip.keyframes.some((k: any) => k.property === "playback_rate");

              // eslint-disable-next-line lazynext/prefer-object-params
              const getEasingT = (kfs: any[], i: number, f: number) => {
                let t = (f - kfs[i].frame) / (kfs[i+1].frame - kfs[i].frame);
                if (kfs[i].easing === "ease-in") t = t * t;
                else if (kfs[i].easing === "ease-out") t = t * (2.0 - t);
                else if (kfs[i].easing === "ease-in-out") t = t * t * (3.0 - 2.0 * t);
                else if (kfs[i].easing === "step") t = 0.0;
                return t;
              };

              // eslint-disable-next-line lazynext/prefer-object-params
              const getInterpolatedProperty = (prop: string, f: number, defaultValue: number) => {
                if (!clip.keyframes) return defaultValue;
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const kfs = clip.keyframes.filter((k: any) => k.property === prop);
                if (kfs.length === 0) return defaultValue;
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                kfs.sort((a: any, b: any) => a.frame - b.frame);
                if (f <= kfs[0].frame) return kfs[0].value;
                if (f >= kfs[kfs.length - 1].frame) return kfs[kfs.length - 1].value;
                for (let i = 0; i < kfs.length - 1; i++) {
                  if (f >= kfs[i].frame && f <= kfs[i+1].frame) {
                    const t = getEasingT(kfs, i, f);
                    return kfs[i].value + (kfs[i+1].value - kfs[i].value) * t;
                  }
                }
                return defaultValue;
              };

              if (hasSpeedKeyframes) {
                for (let f = 0; f < currentLocalFrame; f++) {
                  initialMediaFrame += getInterpolatedProperty("playback_rate", f, clip.playback_rate || 1.0);
                }
              } else {
                initialMediaFrame += currentLocalFrame * (clip.playback_rate || 1.0);
              }

              const sourceOffset = initialMediaFrame / fps;

              // Apply playbackRate
              const initialPlaybackRate = getInterpolatedProperty("playback_rate", currentLocalFrame > 0 ? currentLocalFrame : 0, clip.playback_rate ?? 1.0);
              source.playbackRate.setValueAtTime(initialPlaybackRate, ctx.currentTime);

              if (hasSpeedKeyframes) {
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const kfs = clip.keyframes.filter((k: any) => k.property === "playback_rate").sort((a: any, b: any) => a.frame - b.frame);
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                kfs.forEach((k: any) => {
                  const keyframeGlobalSeconds = clipStartInSeconds + (k.frame / fps);
                  if (keyframeGlobalSeconds >= currentSeconds) {
                    source.playbackRate.linearRampToValueAtTime(Math.max(0.01, k.value), ctx.currentTime + (keyframeGlobalSeconds - currentSeconds));
                  }
                });
              }


              // Local time inside the clip relative to 0

              // Apply Volume
              const initialVolume = getInterpolatedProperty("volume", currentLocalFrame > 0 ? currentLocalFrame : 0, clip.volume ?? 1.0);
              gainNode.gain.setValueAtTime(initialVolume, ctx.currentTime);

              if (clip.keyframes) {
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const kfs = clip.keyframes.filter((k: any) => k.property === "volume");
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                kfs.forEach((k: any) => {
                  const keyframeGlobalSeconds = clipStartInSeconds + (k.frame / fps);
                  if (keyframeGlobalSeconds >= currentSeconds) {
                    gainNode.gain.linearRampToValueAtTime(k.value, ctx.currentTime + (keyframeGlobalSeconds - currentSeconds));
                  }
                });
              }

              // Apply Transitions Fades
              if (clip.transitions) {
                if (clip.transitions.in && clip.transitions.in.duration_frames > 0) {
                  const fadeInEndSeconds = clipStartInSeconds + (clip.transitions.in.duration_frames / fps);
                  if (currentSeconds < fadeInEndSeconds) {
                    // Start from 0
                    gainNode.gain.setValueAtTime(0, ctx.currentTime);
                    gainNode.gain.linearRampToValueAtTime(initialVolume, ctx.currentTime + (fadeInEndSeconds - currentSeconds));
                  }
                }
                if (clip.transitions.out && clip.transitions.out.duration_frames > 0) {
                  const clipEndSeconds = clipStartInSeconds + (clip.duration_frames / fps);
                  const fadeOutStartSeconds = clipEndSeconds - (clip.transitions.out.duration_frames / fps);
                  if (currentSeconds < fadeOutStartSeconds) {
                    gainNode.gain.setValueAtTime(initialVolume, ctx.currentTime + (fadeOutStartSeconds - currentSeconds));
                    gainNode.gain.linearRampToValueAtTime(0, ctx.currentTime + (clipEndSeconds - currentSeconds));
                  } else if (currentSeconds >= fadeOutStartSeconds && currentSeconds < clipEndSeconds) {
                    // Already inside the fade out
                    const fadeProgress = (currentSeconds - fadeOutStartSeconds) / (clip.transitions.out.duration_frames / fps);
                    const currentFadeVolume = initialVolume * (1.0 - fadeProgress);
                    gainNode.gain.setValueAtTime(currentFadeVolume, ctx.currentTime);
                    gainNode.gain.linearRampToValueAtTime(0, ctx.currentTime + (clipEndSeconds - currentSeconds));
                  }
                }
              }

              // Apply Pan
              const pannerNode = ctx.createStereoPanner();
              const initialPan = getInterpolatedProperty("pan", currentLocalFrame > 0 ? currentLocalFrame : 0, clip.pan ?? 0.0);
              pannerNode.pan.setValueAtTime(initialPan, ctx.currentTime);

              if (clip.keyframes) {
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const pkfs = clip.keyframes.filter((k: any) => k.property === "pan");
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                pkfs.forEach((k: any) => {
                  const keyframeGlobalSeconds = clipStartInSeconds + (k.frame / fps);
                  if (keyframeGlobalSeconds >= currentSeconds) {
                    pannerNode.pan.linearRampToValueAtTime(k.value, ctx.currentTime + (keyframeGlobalSeconds - currentSeconds));
                  }
                });
              }

              // Audio FX (EQ)
              const bassNode = ctx.createBiquadFilter();
              bassNode.type = 'lowshelf';
              bassNode.frequency.value = 250;
              bassNode.gain.value = clip.audio_fx?.bass || 0;

              const midNode = ctx.createBiquadFilter();
              midNode.type = 'peaking';
              midNode.frequency.value = 1000;
              midNode.Q.value = 1;
              midNode.gain.value = clip.audio_fx?.mid || 0;

              const trebleNode = ctx.createBiquadFilter();
              trebleNode.type = 'highshelf';
              trebleNode.frequency.value = 4000;
              trebleNode.gain.value = clip.audio_fx?.treble || 0;

              source.connect(bassNode);
              bassNode.connect(midNode);
              midNode.connect(trebleNode);
              trebleNode.connect(pannerNode);
              pannerNode.connect(gainNode);

              gainNode.connect(ctx.destination);
              if (audioDestRef.current) {
                gainNode.connect(audioDestRef.current);
              }

              const startDelay = clipStartInSeconds > currentSeconds ? clipStartInSeconds - currentSeconds : 0;
              const offsetIntoClip = clipStartInSeconds > currentSeconds ? 0 : currentSeconds - clipStartInSeconds;


              const mediaOffset = ((clip.media_offset_frames || 0) / fps) + (offsetIntoClip * initialPlaybackRate);

              if (currentSeconds >= clipStartInSeconds && currentSeconds < clipStartInSeconds + (clip.duration_frames / fps)) {
                source.start(ctx.currentTime, mediaOffset);
                activeSourcesRef.current.push(source);
              } else if (currentSeconds < clipStartInSeconds) {
                // Schedule for future if playhead is before the clip
                source.start(ctx.currentTime + startDelay, mediaOffset);
                activeSourcesRef.current.push(source);
              }
            }
          }
        });
      });
    } else {
      // Stop all active sources when paused
      activeSourcesRef.current.forEach((source: AudioBufferSourceNode) => {
        try { source.stop(); } catch (e) {}
      });
      activeSourcesRef.current = [];
    }
  }, [isPlaying, projectData.tracks, assets]);

  // eslint-disable-next-line lazynext/prefer-object-params
  const handleDragStart = (e: React.DragEvent, asset: any) => {
    e.dataTransfer.setData("application/json", JSON.stringify({
      type: "new_asset",
      // Exclude File/Buffer objects which can't be JSON serialized cleanly
      id: asset.id,
      name: asset.name,
      assetType: asset.type,
      duration_frames: asset.duration_frames,
      color: asset.color,
      peaks: asset.peaks
    }));
    e.dataTransfer.effectAllowed = "copy";
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const isAudio = file.type.startsWith("audio/");
    const isVideo = file.type.startsWith("video/");

    if (!isAudio && !isVideo) return;

    const objectUrl = URL.createObjectURL(file);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const newAsset: any = {
      id: `asset-${Date.now()}`,
      type: isAudio ? "audio" : "video",
      name: file.name,
      duration_frames: 600, // Default 10s
      color: isAudio ? "bg-amber-600/80 border-amber-400 hover:bg-amber-500" : "bg-indigo-600/80 border-indigo-400 hover:bg-indigo-500",
      file,
      url: objectUrl
    };

    if (isAudio || isVideo) {
      try {
        const arrayBuffer = await file.arrayBuffer();
        // eslint-disable-next-line @typescript-eslint/no-unsafe-type-assertion
        const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
        const audioBuffer = await audioCtx.decodeAudioData(arrayBuffer);

        if (isAudio || isVideo) {
          const channelData = audioBuffer.getChannelData(0);
          const peaks = [];
          const numPeaks = 200;
          const step = Math.floor(channelData.length / numPeaks);

          for (let i = 0; i < numPeaks; i++) {
            let max = 0;
            for (let j = 0; j < step; j++) {
              const val = Math.abs(channelData[i * step + j]);
              if (val > max) max = val;
            }
            peaks.push(max);
          }
          newAsset.peaks = peaks;
          // Only override duration for pure audio, video gets duration from video metadata later if we implement it, 
          // actually let's use audio duration for video too if it's longer.
          newAsset.duration_frames = Math.ceil(audioBuffer.duration * 60);
        }

        newAsset.audioBuffer = audioBuffer;
      } catch (err) {
        console.warn("Could not decode audio track (may not exist):", err);
      }
    }

    if (isVideo) {
      try {
        const video = document.createElement("video");
        video.src = objectUrl;
        video.muted = true;
        video.crossOrigin = "anonymous";
        await new Promise((resolve) => {
          video.onloadeddata = () => resolve(true);
        });

        // Seek to 1 second or half duration
        video.currentTime = Math.min(1, video.duration / 2 || 0);
        await new Promise((resolve) => {
          video.onseeked = () => resolve(true);
        });

        const canvas = document.createElement("canvas");
        canvas.width = 160;
        canvas.height = 90;
        const ctx = canvas.getContext("2d");
        if (ctx) {
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          newAsset.thumbnail = canvas.toDataURL("image/jpeg", 0.7);
        }
      } catch (err) {
        console.warn("Could not generate thumbnail for video:", err);
      }
    }


    setAssets(prev => [...prev, newAsset]);
  };

  const handleFontUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
      const arrayBuffer = await file.arrayBuffer();
      // Use the filename (without extension) as the font family name
      const familyName = file.name.replace(/\.[^/.]+$/, "");
      const font = new FontFace(familyName, arrayBuffer);
      await font.load();
      document.fonts.add(font);
      setCustomFonts(prev => {
        if (!prev.includes(familyName)) return [...prev, familyName];
        return prev;
      });
      // Optionally apply to selected clip immediately
      if (selectedClipId) {
        updateSelectedClip({ font_family: familyName });
      }
    } catch (err) {
      console.warn("Failed to load custom font:", err);
    }
  };

  return (
    <div className="flex h-full w-full">
      {/* Sidebar */}
      <aside 
        className={`${mediaPoolPos.floating ? 'fixed z-50 rounded-xl shadow-[0_10px_40px_rgba(0,0,0,0.8)] resize border border-zinc-700 bg-zinc-900/95 backdrop-blur overflow-hidden flex flex-col' : 'border-r border-zinc-800 bg-zinc-900 flex flex-col h-full shrink-0'} transition-shadow`}
        style={mediaPoolPos.floating ? { left: mediaPoolPos.x, top: mediaPoolPos.y, width: 300, height: 600 } : { width: sidebarWidth }}
      >
        {/* Floating Header */}
        {mediaPoolPos.floating && (
           // eslint-disable-next-line jsx-a11y/no-static-element-interactions
           <div 
             className="h-8 bg-zinc-800 flex items-center justify-between px-3 cursor-move border-b border-zinc-700 select-none"
             onMouseDown={(e: React.MouseEvent) => {
                const startX = e.clientX - mediaPoolPos.x;
                const startY = e.clientY - mediaPoolPos.y;
                const onMove = (ev: MouseEvent) => setMediaPoolPos(p => ({ ...p, x: ev.clientX - startX, y: ev.clientY - startY }));
                const onUp = () => { window.removeEventListener('mousemove', onMove); window.removeEventListener('mouseup', onUp); };
                window.addEventListener('mousemove', onMove);
                window.addEventListener('mouseup', onUp);
             }}
           >
             <div className="flex items-center gap-2">
                <span className="text-[10px] text-zinc-400 font-medium tracking-wide">MEDIA POOL</span>
                <label className="flex items-center gap-1.5 cursor-pointer ml-4" title="Split Audio/Video on Import">
                  <input 
                    type="checkbox" 
                    checked={splitAudioVideoOnImport}
                    onChange={(e) => setSplitAudioVideoOnImport(e.target.checked)}
                    className="w-3 h-3 bg-zinc-800 border-zinc-700 rounded accent-indigo-500 cursor-pointer"
                  />
                  <span className="text-[9px] text-zinc-500 uppercase">Split A/V</span>
                </label>
              </div>
              <button onClick={() => setMediaPoolPos(p => ({...p, floating: false}))} className="text-zinc-400 hover:text-white p-0.5 rounded hover:bg-zinc-700">
                <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
           </div>
        )}

        <div className="flex border-b border-zinc-800 items-center">
          <button 
            className={`flex-1 py-3 text-xs font-semibold tracking-wider transition-colors ${sidebarTab === 'media' ? 'text-indigo-400 border-b-2 border-indigo-500' : 'text-zinc-500 hover:text-zinc-300'}`}
            onClick={() => setSidebarTab('media')}
          >MEDIA</button>
          <button 
            className={`flex-1 py-3 text-xs font-semibold tracking-wider transition-colors ${sidebarTab === 'titles' ? 'text-indigo-400 border-b-2 border-indigo-500' : 'text-zinc-500 hover:text-zinc-300'}`}
            onClick={() => setSidebarTab('titles')}
          >TITLES</button>
          <button 
            className={`flex-1 py-3 text-[10px] font-semibold tracking-wider transition-colors ${sidebarTab === 'effects' ? 'text-indigo-400 border-b-2 border-indigo-500' : 'text-zinc-500 hover:text-zinc-300'}`}
            onClick={() => setSidebarTab('effects')}
          >FX</button>
          <button 
            className={`flex-1 py-3 text-[10px] font-semibold tracking-wider transition-colors ${sidebarTab === 'transitions' ? 'text-indigo-400 border-b-2 border-indigo-500' : 'text-zinc-500 hover:text-zinc-300'}`}
            onClick={() => setSidebarTab('transitions')}
          >TRANS</button>
          <button 
            className={`flex-1 py-3 text-[10px] font-semibold tracking-wider transition-colors ${sidebarTab === 'history' ? 'text-indigo-400 border-b-2 border-indigo-500' : 'text-zinc-500 hover:text-zinc-300'}`}
            onClick={() => setSidebarTab('history')}
            title="Undo History"
          >HIST</button>
          <button 
            className={`flex-1 py-3 text-[10px] font-semibold tracking-wider transition-colors ${sidebarTab === 'transcript' ? 'text-indigo-400 border-b-2 border-indigo-500' : 'text-zinc-500 hover:text-zinc-300'}`}
            onClick={() => setSidebarTab('transcript')}
            title="AI Transcript"
          >TEXT</button>
          <button 
            className={`flex-1 py-3 text-[10px] font-semibold tracking-wider transition-colors ${sidebarTab === 'index' ? 'text-indigo-400 border-b-2 border-indigo-500' : 'text-zinc-500 hover:text-zinc-300'}`}
            onClick={() => setSidebarTab('index')}
          >INDEX</button>
          <button 
            className={`flex-1 py-3 text-[10px] font-semibold tracking-wider transition-colors ${sidebarTab === 'fusion' ? 'text-indigo-400 border-b-2 border-indigo-500' : 'text-zinc-500 hover:text-zinc-300'}`}
            onClick={() => setSidebarTab('fusion')}
            title="Node Compositing"
          >FUSION</button>
          {/* Cloud Asset Library (Phase 196) */}
          <button 
            className={`flex-1 py-3 text-[10px] font-semibold tracking-wider transition-colors ${sidebarTab === 'stock' ? 'text-indigo-400 border-b-2 border-indigo-500' : 'text-zinc-500 hover:text-zinc-300'}`}
            onClick={() => setSidebarTab('stock')}
            title="Cloud Asset Library"
          >STOCK</button>
        </div>
        {/* ... (sidebar content) */}


        {sidebarTab === 'media' && (
          <div className="px-4 pt-4 pb-2 flex flex-col gap-3 shrink-0">
            <div className="relative">
              <svg className="w-4 h-4 text-zinc-500 absolute left-3 top-1/2 -translate-y-1/2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
              <input 
                type="text" 
                placeholder="Search Media..." 
                value={mediaSearchQuery}
                onChange={e => setMediaSearchQuery(e.target.value)}
                className="w-full bg-zinc-950 border border-zinc-800 rounded pl-9 pr-3 py-1.5 text-xs text-white placeholder-zinc-500 focus:outline-none focus:border-indigo-500 transition-colors"
              />
            </div>
            <div className="flex gap-1 bg-zinc-950 p-1 rounded border border-zinc-800 overflow-x-auto custom-scrollbar">
              {['all', 'video', 'audio', 'image'].map(f => (
                <button 
                  key={f}
                  // eslint-disable-next-line @typescript-eslint/no-unsafe-type-assertion
                  onClick={() => setMediaFilter(f as any)}
                  className={`flex-1 px-2 py-1 text-[10px] uppercase font-bold rounded transition-colors ${mediaFilter === f ? 'bg-zinc-800 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
                >
                  {f}
                </button>
              ))}
            </div>

            {/* Smart Bins (Phase 182) */}
            <div className="flex gap-1 overflow-x-auto custom-scrollbar mt-1">
              <span className="text-[9px] text-zinc-500 font-bold uppercase py-1 mr-1 shrink-0">Smart Bins:</span>
              {['B-Roll', 'Interviews', 'Action', 'Day Exterior'].map(bin => (
                <button key={bin} className="shrink-0 px-2 py-0.5 text-[9px] bg-indigo-500/10 text-indigo-300 border border-indigo-500/20 rounded-full hover:bg-indigo-500/20 transition-colors whitespace-nowrap">
                  {bin}
                </button>
              ))}
