                    {/* Simulated waveform data */}
                    {Array.from({length: 256}, (_, x) => {
                      const baseY = 40 + Math.sin(x * 0.05 + frame * 0.02) * 15 + Math.sin(x * 0.12) * 8;
                      // eslint-disable-next-line react-hooks/purity
                      const scatter = Math.random() * 20 - 10;
