							<Link href="/" className="flex items-center gap-3">
								<Image
									src={DEFAULT_LOGO_URL}
									alt="Lazynext Logo"
									width={32}
									height={32}
								/>
							</Link>
						</ContextMenuTrigger>
						<ContextMenuContent>
							<ContextMenuItem
								onClick={async () => {
									await navigator.clipboard.writeText(new URL(DEFAULT_LOGO_URL, window.location.origin).toString());
